#include<bits/stdc++.h>
#include<bits/extc++.h>
using namespace std;
using namespace __gnu_pbds;
unordered_map<string,bool> mp,vis;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        string s;
        cin>>s;
        mp[s]=true;
    }
    for(int i=1;i<=m;i++)
    {
        string s;
        cin>>s;
        if(mp.find(s)!=mp.end())
        {
            printf("-1\n");
            continue;
        }
        vis.clear();
        int siz=s.size();
        int ans=0;
        for(char c='a';c<='z';c++)
        {
            for(int j=0;j<siz;j++)
            {
                string str="";
                for(int k=0;k<j;k++)
                {
                    str.push_back(s[k]);
                }
                str.push_back(c);
                for(int k=j;k<siz;k++)
                {
                    str.push_back(s[k]);
                }
                if(vis.find(str)!=vis.end())
                {
                    continue;
                }
                if(mp.find(str)!=mp.end())
                {
                    vis[str]=true;
                    // cout<<str<<endl;
                    ans++;
                }
            }
            string str=s+c;
            if(vis.find(str)!=vis.end())
            {
                continue;
            }
            if(mp.find(str)!=mp.end())
            {
                vis[str]=true;
                // cout<<str<<endl;
                ans++;
            }
        }
        for(int j=0;j<siz;j++)
        {
            string str="";
            for(int k=0;k<j;k++)
            {
                str.push_back(s[k]);
            }
            for(int k=j+1;k<siz;k++)
            {
                str.push_back(s[k]);
            }
            if(vis.find(str)!=vis.end())
            {
                continue;
            }
            if(mp.find(str)!=mp.end())
            {
                vis[str]=true;
                // cout<<str<<endl;
                ans++;
            }
        }
        for(char c='a';c<='z';c++)
        {
            for(int j=0;j<siz;j++)
            {
                string str=s;
                str[j]=c;
                if(vis.find(str)!=vis.end())
                {
                    continue;
                }
                if(mp.find(str)!=mp.end())
                {
                    vis[str]=true;
                    ans++;
                    // cout<<str<<endl;
                }
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
